49	/// Commits-on-drop guard armed while the fill closure runs: a
50	/// panic unwinding through `send_with` must not abandon the
51	/// claimed position (the consumer would wait there forever),
52	/// so drop-without-disarm publishes the tombstoned commit the
53	/// consumer releases without delivering.
54	struct TombstoneOnUnwind<'s> {
55	    /// The claimed slot's seq word.
56	    seq: &'s AtomicU32,
57	    /// The commit value (`pos + 1`).
58	    commit: u32,
59	}
