61	impl Drop for TombstoneOnUnwind<'_> {
62	    /// Unwind path only — the normal path disarms with
63	    /// `mem::forget`.
64	    fn drop(&mut self) {
65	        // Release: the (garbage) slot bytes must still be a
66	        // well-defined handoff; the consumer skips the message
67	        // but touches the seq protocol state.
68	        self.seq
69	            .store(self.commit.wrapping_add(TOMBSTONE), Ordering::Release);
70	    }
71	}
