1	//! Report band boundaries and label styles: the single source of
2	//! truth for the min/z/p/n/max ladder that
3	//! [`crate::harness::print_report`] renders, documented by the
4	//! README's boundary-ladder table (pinned by this module's tests).
5	//!
6	//! - Familiar deciles in the body; nines/zeros tails generated
7	//!   from [`Z_DEPTH`]/[`N_DEPTH`]. Fractions and names come from
8	//!   one structural description, so the label styles can never
9	//!   drift apart and deepening a tail is a one-constant change.
10	//! - `band_table.rs` and `probe.rs` still carry their own older
11	//!   percentile ladders; unifying them onto this module is part
12	//!   of the probe-based-harness conversion todo.
13	
14	/// Fast-tail depth: the lowest tail boundary is `z{Z_DEPTH}`.
15	const Z_DEPTH: i32 = 4;
16	/// Slow-tail depth: the highest tail boundary is `n{N_DEPTH}`.
17	/// Deeper than [`Z_DEPTH`] because a latency distribution is
18	/// floored below (nothing beats the fast path) and open above.
19	const N_DEPTH: i32 = 10;
20	
21	/// Band-label style for the report's histogram rows, selected by
22	/// the `--band-labels` CLI flag.
23	///
24	/// - `Zpn` — nines/zeros + decile names (`z3`, `p50`, `n4`).
25	/// - `Frac` — literal boundary fractions with `_` grouping
26	///   (`0.001`, `0.50`, `0.999_9`).
27	/// - `Both` — zpn and fraction side by side (`n4  0.999_9`);
28	///   the default: the juxtaposition teaches the zpn vocabulary.
29	#[derive(Debug, Clone, Copy, PartialEq, Eq, clap::ValueEnum)]
30	pub enum BandLabels {
31	    Zpn,
32	    Frac,
33	    Both,
34	}
35	
36	impl BandLabels {
37	    /// Lowercase name used on the CLI and in the report header's
38	    /// `labels=` metadata.
39	    pub fn as_str(self) -> &'static str {
40	        match self {
41	            BandLabels::Zpn => "zpn",
42	            BandLabels::Frac => "frac",
43	            BandLabels::Both => "both",
44	        }
45	    }
46	}
47	
48	/// One report band boundary: its CDF fraction plus its rendered
49	/// name in each label style.
50	pub struct Boundary {
51	    /// Fraction of samples at or below the boundary (CDF).
52	    pub pct: f64,
53	    /// nines/zeros / decile name (`z3`, `p50`, `n4`).
54	    pub zpn: String,
55	    /// Literal-fraction name, `_`-grouped (`0.001`, `0.999_9`).
56	    pub frac: String,
57	}
58	
59	impl Boundary {
60	    /// Row label for this boundary in the given style. min/max
61	    /// carry no fraction, so `both` prints them bare; elsewhere
62	    /// `both` pads zpn to its 3-char max so the fraction column
63	    /// aligns.
64	    pub fn label(&self, style: BandLabels) -> String {
65	        match style {
66	            BandLabels::Zpn => self.zpn.clone(),
67	            BandLabels::Frac => self.frac.clone(),
68	            BandLabels::Both if self.zpn == self.frac => self.zpn.clone(),
69	            BandLabels::Both => format!("{:<3} {}", self.zpn, self.frac),
70	        }
71	    }
72	
73	    /// Bare style-name for this boundary, used to build the
74	    /// trimmed-stat range label. `both` reuses the `zpn` name (as
75	    /// the trim label always did) rather than the padded pair —
76	    /// `z4`, not `z4  0.000_1` — so it reads cleanly in a range.
77	    pub fn trim_name(&self, style: BandLabels) -> &str {
78	        match style {
79	            BandLabels::Frac => &self.frac,
80	            BandLabels::Zpn | BandLabels::Both => &self.zpn,
81	        }
82	    }
83	}
84	
85	/// Group `digits` in threes with `_` so deep nines stay
86	/// countable at a glance, e.g. `"99999"` → `"999_99"`.
87	fn group3(digits: &str) -> String {
88	    let mut out = String::new();
89	    for (i, c) in digits.chars().enumerate() {
90	        if i > 0 && i % 3 == 0 {
91	            out.push('_');
92	        }
93	        out.push(c);
94	    }
95	    out
96	}
97	
98	/// The report's band boundaries, generated from
99	/// [`Z_DEPTH`]/[`N_DEPTH`]: familiar deciles in the body,
100	/// nines/zeros notation in both tails.
101	///
102	/// - `nK`/`zK` mark the boundary with a fraction 10^-K of
103	///   samples above (n) or below (z): n2 ≡ p99, n3 ≡ p99.9, …
104	///   and z2 ≡ p1, z3 ≡ p0.1, z4. "K nines" is standard
105	///   engineering shorthand for proportions near one
106	///   (nines = -log10(1-x)); zK is this project's mirror of it
107	///   for the fast tail.
108	/// - Deep bands populate only when the run has enough samples;
109	///   empty bands are skipped in the output.
110	pub fn boundaries() -> Vec<Boundary> {
111	    let mut v = vec![Boundary {
112	        pct: 0.0,
113	        zpn: "min".to_string(),
114	        frac: "min".to_string(),
115	    }];
116	    for k in (2..=Z_DEPTH).rev() {
117	        v.push(Boundary {
118	            pct: 10f64.powi(-k),
119	            zpn: format!("z{k}"),
120	            frac: format!("0.{}", group3(&("0".repeat(k as usize - 1) + "1"))),
121	        });
122	    }
123	    for d in 1..=9 {
124	        v.push(Boundary {
125	            pct: d as f64 / 10.0,
126	            zpn: format!("p{d}0"),
127	            frac: format!("0.{d}0"),
128	        });
129	    }
130	    for k in 2..=N_DEPTH {
131	        v.push(Boundary {
132	            pct: 1.0 - 10f64.powi(-k),
133	            zpn: format!("n{k}"),
134	            frac: format!("0.{}", group3(&"9".repeat(k as usize))),
135	        });
136	    }
137	    v.push(Boundary {
138	        pct: 1.0,
139	        zpn: "max".to_string(),
140	        frac: "max".to_string(),
141	    });
142	    v
143	}
144	
145	#[cfg(test)]
146	mod tests {
147	    use super::*;
148	
149	    #[test]
150	    fn generated_boundaries_match_documented_ladder() {
151	        let b = boundaries();
152	        let zpn: Vec<&str> = b.iter().map(|x| x.zpn.as_str()).collect();
153	        assert_eq!(
